import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"PRD-002 — Mission Configurator","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-002.md","filePath":"prd/PRD-002.md"}'),s={name:"prd/PRD-002.md"};function r(n,e,l,h,c,d){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="prd-002-—-mission-configurator" tabindex="-1">PRD-002 — Mission Configurator <a class="header-anchor" href="#prd-002-—-mission-configurator" aria-label="Permalink to &quot;PRD-002 — Mission Configurator&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Sources · 04_Technical_Architecture.md §lambert · 02_Project_Concept.md §six-screens Audiences · curious learner, STEM student (PA §audiences) Promises · real physics, educational at every level (PA §promises) Principles · physics first, fail honestly (PA §principles) Why this is a PRD · This screen lets a person experience the delta-v budget and launch window constraint as a felt reality, not an abstract fact. Failure is a valid outcome. The educational moment is in running out of delta-v.</p></blockquote><p>A student who knows the Hohmann transfer from a textbook is looking at a grid of colours. Orange cells are expensive. Blue cells are cheap. They drag the departure slider to a bad month. The orange intensifies. They select their launch vehicle. The rocket equation solves. They&#39;re 0.8 km/s short. The screen doesn&#39;t hide this. The student now understands the delta-v budget in a way the textbook never achieved.</p><h2 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h2><p>The porkchop plot is one of the most important tools in mission planning. It shows every possible departure and arrival combination for a multi-year window, coloured by delta-v cost. Professional mission planners use it every day. It is completely invisible to the public.</p><p>The curious person who watched a Mars landing and wondered &quot;why did they launch in July?&quot; has no way to answer that question with their own hands. The answer is in a porkchop plot. They&#39;ve never seen one.</p><h2 id="the-experience" tabindex="-1">The experience <a class="header-anchor" href="#the-experience" aria-label="Permalink to &quot;The experience&quot;">​</a></h2><p>The user arrives at the PLAN screen. A 11,200-cell porkchop plot has already been computed — departure dates on the X axis, arrival dates on the Y axis, delta-v cost as colour. Blue is cheap. Orange is expensive. The launch windows are immediately visible as blue valleys.</p><p>They hover over a cell. A tooltip shows departure date, arrival date, transit time, and delta-v. They click a cell in a blue valley. The right panel shows: vehicle selection, payload mass, computed propellant, and a FLY THIS MISSION button. They select Falcon Heavy. The Tsiolkovsky equation solves. Their payload of 2,500 kg is viable. They click FLY.</p><p>They click a cell in a deep orange region. The same calculation runs. They&#39;re short. The panel shows the shortfall clearly — &quot;Δv deficit: 1.2 km/s.&quot; They either choose a larger vehicle or accept that this window doesn&#39;t work. The screen has taught them something about orbital mechanics through failure.</p><h2 id="why-now" tabindex="-1">Why now <a class="header-anchor" href="#why-now" aria-label="Permalink to &quot;Why now&quot;">​</a></h2><p>The configurator is Act 2 — it comes after the explorer establishes the geometry and before the arc visualises the flight. Without it, the fly screen is a demo; with it, the fly screen is the result of a decision the user made.</p><h2 id="success-looks-like" tabindex="-1">Success looks like <a class="header-anchor" href="#success-looks-like" aria-label="Permalink to &quot;Success looks like&quot;">​</a></h2><p>A user selects a bad departure window, runs out of delta-v, switches to a good window, and succeeds — and can explain why the windows are different.</p><p>A STEM student verifies that the delta-v values in the porkchop plot match what they computed from the vis-viva equation and the rocket equation.</p><p>The FLY THIS MISSION navigation feels like a natural consequence of completing the planning step.</p><h2 id="out-of-scope" tabindex="-1">Out of scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of scope&quot;">​</a></h2><ul><li>Multi-leg trajectories (Earth-Venus-Mars gravity assist)</li><li>Atmospheric entry delta-v</li><li>Custom rocket builder (vehicle selection from a fixed list only)</li><li>Saving or exporting a mission configuration</li></ul><h2 id="the-sharpest-threat" tabindex="-1">The sharpest threat <a class="header-anchor" href="#the-sharpest-threat" aria-label="Permalink to &quot;The sharpest threat&quot;">​</a></h2><p>The porkchop plot only means something if the user understands what the colours represent. If the axis labels and colour scale aren&#39;t immediately legible, the plot is visual noise. The educational moment depends on the plot being intuitive enough to read without explanation.</p><h2 id="open-threads" tabindex="-1">Open threads <a class="header-anchor" href="#open-threads" aria-label="Permalink to &quot;Open threads&quot;">​</a></h2><ul><li>UXS-002 for full visual contract</li><li>RFC-003 for Lambert worker protocol (the computation that generates the plot)</li><li>RFC-002 for mission schema (what data is passed to the fly screen)</li><li>RFC-006 for porkchop plot mobile interaction model — the desktop tap-to-select cannot work on mobile at native cell size</li><li>ADR-008 locks the Lambert solver in a Web Worker</li><li>ADR-018 locks mobile-first design approach</li></ul><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Prototype: <code>docs/prototypes/P02_mission-configurator.html</code></li><li>Concept: <code>docs/concept/02_Project_Concept.md §six-screens</code></li></ul>',24)])])}const m=t(s,[["render",r]]);export{u as __pageData,m as default};
